\begin{tikzpicture}
    % 画脸部圆圈
    \draw[thick] (0,0) circle (2cm);

    % 画眼睛
    \fill (-0.7,0.7) circle (0.2cm);
    \fill (0.7,0.7) circle (0.2cm);

    % 画嘴巴
    \draw[thick] (-0.7,-0.7) arc[start angle=30, end angle=150, radius=1cm];

    % 画泪水
    \draw[blue, thick] (-0.7,0.5) -- (-0.7,-0.5);
    \draw[blue, thick] (0.7,0.5) -- (0.7,-0.5);
\end{tikzpicture}
